import React from 'react';

function GifAnimationControlledByScroll({ scrollPercentage, gifs }) {
  return (
    <div className="GifAnimationControlledByScroll">
      {gifs.map((gif, index) => (
        <div
          key={index}
          className="GifContainer"
          style={{
            position: 'relative',
            width: '100%',
            height: '100vh',
          }}
        >
          <img
            src={gif.src}
            alt={`Animated GIF ${index + 1}`}
            style={{
              position: 'absolute',
              top: gif.position.top,
              left: gif.position.left,
              width: gif.size.width,
              height: gif.size.height,
              animationDuration: `${100 - scrollPercentage}%`, // Ajusta la velocidad de la animación del GIF
            }}
          />
        </div>
      ))}
    </div>
  );
}

export default GifAnimationControlledByScroll;
